export default function Rodape() {
  const footer = ["Sobre Nós", "Política de Privacidade", "Termos e Condições"];
  return (
    <div>
      <div className="bg-branco w-full mt-16">
        <span class="h-1 bg-rodape lg:w-[94%] absolute mt-5 ml-[3vw]"></span>
        <ul className="items-center inline-flex h-24">
          {footer.map((item) => {
            return (
              <li className="text-base text-rodape ml-[3vw] pr-[3vw]">
                {item}
              </li>
            );
          })}
        </ul>

        <span class="h-1 bg-rodape lg:w-[94%] absolute mb-[-25px] ml-[3vw]"></span>
      </div>
    </div>
  );
}
